type userService struct {
	store *userStore
}

func (u *userService) Health(ctx context.Context, _ *HealthRequest) (*HealthResponse, error) {
	return &HealthResponse{Status: "ok"}, nil
}
func (u *userService) GetUser(ctx context.Context, req *GetUserRequest) (*User, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.store.mu.RLock()
	defer u.store.mu.RUnlock()
	usr := u.store.users[req.Id]
	if usr == nil {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	cp := *usr
	return &cp, nil
}
func (u *userService) CreateUser(ctx context.Context, req *CreateUserRequest) (*User, error) {
	email := strings.TrimSpace(req.Email)
	name := strings.TrimSpace(req.Name)
	if email == "" {
		return nil, status.Error(codes.InvalidArgument, "email is required")
	}
	now := time.Now().Unix()
	u.store.mu.Lock()
	defer u.store.mu.Unlock()
	id := u.store.nextID()
	usr := &User{Id: id, Email: email, Name: name, CreatedAt: now, UpdatedAt: now}
	u.store.users[id] = usr
	cp := *usr
	return &cp, nil
}
func (u *userService) UpdateUser(ctx context.Context, req *UpdateUserRequest) (*User, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.store.mu.Lock()
	defer u.store.mu.Unlock()
	usr := u.store.users[req.Id]
	if usr == nil {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	if strings.TrimSpace(req.Email) != "" {
		usr.Email = strings.TrimSpace(req.Email)
	}
	if strings.TrimSpace(req.Name) != "" {
		usr.Name = strings.TrimSpace(req.Name)
	}
	usr.UpdatedAt = time.Now().Unix()
	cp := *usr
	return &cp, nil
}
func (u *userService) DeleteUser(ctx context.Context, req *DeleteUserRequest) (*HealthResponse, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	u.store.mu.Lock()
	defer u.store.mu.Unlock()
	if _, ok := u.store.users[req.Id]; !ok {
		return nil, status.Error(codes.NotFound, "user not found")
	}
	delete(u.store.users, req.Id)
	return &HealthResponse{Status: "deleted"}, nil
}
func (u *userService) ListUsers(ctx context.Context, req *ListUsersRequest) (*ListUsersResponse, error) {
	limit := int(req.Limit)
	offset := int(req.Offset)
	if limit <= 0 {
		limit = 50
	}
	if limit > 500 {
		limit = 500
	}
	if offset < 0 {
		offset = 0
	}
	q := strings.ToLower(strings.TrimSpace(req.Query))

	u.store.mu.RLock()
	defer u.store.mu.RUnlock()

	all := make([]*User, 0, len(u.store.users))
	for _, usr := range u.store.users {
		if q != "" {
			if !strings.Contains(strings.ToLower(usr.Email), q) && !strings.Contains(strings.ToLower(usr.Name), q) && !strings.Contains(strings.ToLower(usr.Id), q) {
				continue
			}
		}
		cp := *usr
		all = append(all, &cp)
	}
	total := len(all)
	if offset >= total {
		return &ListUsersResponse{Users: []*User{}, Total: int32(total)}, nil
	}
	end := offset + limit
	if end > total {
		end = total
	}
	return &ListUsersResponse{Users: all[offset:end], Total: int32(total)}, nil
}

type orderService struct {
	store     *orderStore
	userStore *userStore
}

func (o *orderService) Health(ctx context.Context, _ *HealthRequest) (*HealthResponse, error) {
	return &HealthResponse{Status: "ok"}, nil
}
func (o *orderService) GetOrder(ctx context.Context, req *GetOrderRequest) (*Order, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	o.store.mu.RLock()
	defer o.store.mu.RUnlock()
	ord := o.store.orders[req.Id]
	if ord == nil {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	cp := *ord
	return &cp, nil
}
func (o *orderService) CreateOrder(ctx context.Context, req *CreateOrderRequest) (*Order, error) {
	userID := strings.TrimSpace(req.UserId)
	if userID == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be > 0")
	}
	currency := strings.ToUpper(strings.TrimSpace(req.Currency))
	if currency == "" {
		currency = "USD"
	}

	o.userStore.mu.RLock()
	_, ok := o.userStore.users[userID]
	o.userStore.mu.RUnlock()
	if !ok {
		return nil, status.Error(codes.FailedPrecondition, "user does not exist")
	}

	now := time.Now().Unix()
	o.store.mu.Lock()
	defer o.store.mu.Unlock()
	id := o.store.nextID()
	ord := &Order{
		Id:        id,
		UserId:    userID,
		Amount:    req.Amount,
		Currency:  currency,
		Status:    "CREATED",
		CreatedAt: now,
		UpdatedAt: now,
	}
	o.store.orders[id] = ord
	cp := *ord
	return &cp, nil
}
func (o *orderService) UpdateOrderStatus(ctx context.Context, req *UpdateOrderStatusRequest) (*Order, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	st := strings.ToUpper(strings.TrimSpace(req.Status))
	if st == "" {
		return nil, status.Error(codes.InvalidArgument, "status is required")
	}
	o.store.mu.Lock()
	defer o.store.mu.Unlock()
	ord := o.store.orders[req.Id]
	if ord == nil {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	ord.Status = st
	ord.UpdatedAt = time.Now().Unix()
	cp := *ord
	return &cp, nil
}
func (o *orderService) CancelOrder(ctx context.Context, req *CancelOrderRequest) (*Order, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	o.store.mu.Lock()
	defer o.store.mu.Unlock()
	ord := o.store.orders[req.Id]
	if ord == nil {
		return nil, status.Error(codes.NotFound, "order not found")
	}
	if ord.Status == "CANCELLED" {
		cp := *ord
		return &cp, nil
	}
	ord.Status = "CANCELLED"
	ord.UpdatedAt = time.Now().Unix()
	cp := *ord
	return &cp, nil
}
func (o *orderService) ListOrders(ctx context.Context, req *ListOrdersRequest) (*ListOrdersResponse, error) {
	limit := int(req.Limit)
	offset := int(req.Offset)
	if limit <= 0 {
		limit = 50
	}
	if limit > 500 {
		limit = 500
	}
	if offset < 0 {
		offset = 0
	}
	userID := strings.TrimSpace(req.UserId)

	o.store.mu.RLock()
	defer o.store.mu.RUnlock()

	all := make([]*Order, 0, len(o.store.orders))
	for _, ord := range o.store.orders {
		if userID != "" && ord.UserId != userID {
			continue
		}
		cp := *ord
		all = append(all, &cp)
	}
	total := len(all)
	if offset >= total {
		return &ListOrdersResponse{Orders: []*Order{}, Total: int32(total)}, nil
	}
	end := offset + limit
	if end > total {
		end = total
	}
	return &ListOrdersResponse{Orders: all[offset:end], Total: int32(total)}, nil
}

type paymentService struct {
	store      *paymentStore
	orderStore *orderStore
	userStore  *userStore
}

func (p *paymentService) Health(ctx context.Context, _ *HealthRequest) (*HealthResponse, error) {
	return &HealthResponse{Status: "ok"}, nil
}
func (p *paymentService) GetPayment(ctx context.Context, req *GetPaymentRequest) (*Payment, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	p.store.mu.RLock()
	defer p.store.mu.RUnlock()
	pmt := p.store.payments[req.Id]
	if pmt == nil {
		return nil, status.Error(codes.NotFound, "payment not found")
	}
	cp := *pmt
	return &cp, nil
}
func (p *paymentService) CreatePayment(ctx context.Context, req *CreatePaymentRequest) (*Payment, error) {
	orderID := strings.TrimSpace(req.OrderId)
	userID := strings.TrimSpace(req.UserId)
	if orderID == "" {
		return nil, status.Error(codes.InvalidArgument, "order_id is required")
	}
	if userID == "" {
		return nil, status.Error(codes.InvalidArgument, "user_id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be > 0")
	}
	currency := strings.ToUpper(strings.TrimSpace(req.Currency))
	if currency == "" {
		currency = "USD"
	}
	method := strings.ToUpper(strings.TrimSpace(req.Method))
	if method == "" {
		method = "CARD"
	}

	p.userStore.mu.RLock()
	_, uok := p.userStore.users[userID]
	p.userStore.mu.RUnlock()
	if !uok {
		return nil, status.Error(codes.FailedPrecondition, "user does not exist")
	}

	p.orderStore.mu.RLock()
	ord := p.orderStore.orders[orderID]
	p.orderStore.mu.RUnlock()
	if ord == nil {
		return nil, status.Error(codes.FailedPrecondition, "order does not exist")
	}
	if ord.UserId != userID {
		return nil, status.Error(codes.PermissionDenied, "order does not belong to user")
	}
	if ord.Currency != currency {
		return nil, status.Error(codes.FailedPrecondition, "currency mismatch with order")
	}
	if req.Amount > ord.Amount {
		return nil, status.Error(codes.FailedPrecondition, "payment amount exceeds order amount")
	}

	now := time.Now().Unix()
	p.store.mu.Lock()
	defer p.store.mu.Unlock()
	id := p.store.nextID()
	pmt := &Payment{
		Id:        id,
		OrderId:   orderID,
		UserId:    userID,
		Amount:    req.Amount,
		Currency:  currency,
		Method:    method,
		Status:    "CAPTURED",
		CreatedAt: now,
		UpdatedAt: now,
	}
	p.store.payments[id] = pmt
	cp := *pmt
	return &cp, nil
}
func (p *paymentService) RefundPayment(ctx context.Context, req *RefundPaymentRequest) (*Payment, error) {
	if strings.TrimSpace(req.Id) == "" {
		return nil, status.Error(codes.InvalidArgument, "id is required")
	}
	if req.Amount <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be > 0")
	}
	p.store.mu.Lock()
	defer p.store.mu.Unlock()
	pmt := p.store.payments[req.Id]
	if pmt == nil {
		return nil, status.Error(codes.NotFound, "payment not found")
	}
	if pmt.Status == "REFUNDED" {
		cp := *pmt
		return &cp, nil
	}
	if req.Amount > pmt.Amount {
		return nil, status.Error(codes.FailedPrecondition, "refund amount exceeds captured amount")
	}
	pmt.Status = "REFUNDED"
	pmt.UpdatedAt = time.Now().Unix()
	cp := *pmt
	return &cp, nil
}
func (p *paymentService) ListPayments(ctx context.Context, req *ListPaymentsRequest) (*ListPaymentsResponse, error) {
	limit := int(req.Limit)
	offset := int(req.Offset)
	if limit <= 0 {
		limit = 50
	}
	if limit > 500 {
		limit = 500
	}
	if offset < 0 {
		offset = 0
	}
	userID := strings.TrimSpace(req.UserId)
	orderID := strings.TrimSpace(req.OrderId)

	p.store.mu.RLock()
	defer p.store.mu.RUnlock()

	all := make([]*Payment, 0, len(p.store.payments))
	for _, pmt := range p.store.payments {
		if userID != "" && pmt.UserId != userID {
			continue
		}
		if orderID != "" && pmt.OrderId != orderID {
			continue
		}
		cp := *pmt
		all = append(all, &cp)
	}
	total := len(all)
	if offset >= total {
		return &ListPaymentsResponse{Payments: []*Payment{}, Total: int32(total)}, nil
	}
	end := offset + limit
	if end > total {
		end = total
	}
	return &ListPaymentsResponse{Payments: all[offset:end], Total: int32(total)}, nil
}

func env(key, def string) string {
	v := strings.TrimSpace(os.Getenv(key))
	if v == "" {
		return def
	}
	return v
}

func main() {
	addr := env("GRPC_ADDR", ":50051")

	lis, err := net.Listen("tcp", addr)
	if err != nil {
		log.Fatalf("listen: %v", err)
	}

	codec := jsonCodec{}
	grpcServer := grpc.NewServer(
		grpc.ForceServerCodec(codec),
	)

	us := newUserStore()
	osr := newOrderStore()
	ps := newPaymentStore()

	RegisterUserServiceServer(grpcServer, &userService{store: us})
	RegisterOrderServiceServer(grpcServer, &orderService{store: osr, userStore: us})
	RegisterPaymentServiceServer(grpcServer, &paymentService{store: ps, orderStore: osr, userStore: us})

	reflection.Register(grpcServer)

	errCh := make(chan error, 1)
	go func() {
		log.Printf("gRPC dev server listening on %s (codec=%s)", addr, codec.Name())
		if err := grpcServer.Serve(lis); err != nil {
			errCh <- err
		}
	}()

	sigCh := make(chan os.Signal, 2)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	select {
	case sig := <-sigCh:
		log.Printf("signal: %s; shutting down", sig.String())
		gracefulStop(grpcServer, 5*time.Second)
	case err := <-errCh:
		if !errors.Is(err, net.ErrClosed) {
			log.Printf("server error: %v", err)
		}
		gracefulStop(grpcServer, 5*time.Second)
	}
}

func gracefulStop(s *grpc.Server, timeout time.Duration) {
	done := make(chan struct{})
	go func() {
		s.GracefulStop()
		close(done)
	}()
	select {
	case <-done:
	case <-time.After(timeout):
		s.Stop()
	}
}

